/**
 * Perception.stories.js — Calibration demos that train the eye to the scale
 *
 * These stories help calibrate perception of duration and easing.
 * Token values align with the baseline token set and benchmark data.
 */

import { SPRING_CONFIGS, cubicBezierCSS } from './tokens.js';
import { springToLinear } from './spring-resolver.js';

export default {
  title: 'Experimental/Perception',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component:
          'Calibration demos for motion perception. ' +
          'DurationThreshold trains the eye to the duration scale. ' +
          'EasingCharacter shows 5 primitive curves on the same track. ' +
          'SpringVsCubic compares a spring and a cubic-bezier at similar durations. ' +
          'ContextCalibration shows appropriate durations on real UI elements.',
      },
    },
  },
};

const baseStyles = `
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f8f8f8; }
  .page { max-width: 960px; margin: 0 auto; padding: 48px 32px; }
  .page-title { font-size: 13px; font-weight: 600; color: #666; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 4px; }
  .page-subtitle { font-size: 22px; font-weight: 700; color: #111; margin-bottom: 8px; }
  .page-desc { font-size: 14px; color: #555; line-height: 1.6; margin-bottom: 40px; max-width: 680px; }
`;

// ---------------------------------------------------------------------------
// Story 1 — DurationThreshold
// ---------------------------------------------------------------------------
const DURATION_REGIONS = [
  { ms: 50,   label: 'Instantaneous',   note: 'Below perceptual threshold — state change without motion', color: '#888' },
  { ms: 100,  label: 'Interactive',     note: 'Interactive window — feels immediate', color: '#007755' },
  { ms: 150,  label: 'Interactive',     note: '', color: '#007755' },
  { ms: 200,  label: 'Interactive',     note: 'Standard UI default — still feels fast', color: '#007755' },
  { ms: 250,  label: 'Interactive',     note: '', color: '#0055bb' },
  { ms: 300,  label: 'Noticeable',      note: 'Transition becomes perceptible', color: '#0055bb' },
  { ms: 400,  label: 'Noticeable',      note: 'Significant state change', color: '#0055bb' },
  { ms: 500,  label: 'Deliberate',      note: 'User expects something meaningful — modal, panel', color: '#7700cc' },
  { ms: 700,  label: 'Deliberate',      note: 'Storytelling territory — use sparingly', color: '#7700cc' },
  { ms: 1000, label: 'Slow',            note: 'Requires clear intent — onboarding, empty states', color: '#c41c1c' },
];

export const DurationThreshold = {
  name: 'Duration threshold',
  render: () => {
    const regionColors = {
      'Instantaneous': '#888',
      'Interactive': '#007755',
      'Noticeable': '#0055bb',
      'Deliberate': '#7700cc',
      'Slow': '#c41c1c',
    };

    const buttons = DURATION_REGIONS.map(d => `
      <button class="dur-btn" data-ms="${d.ms}" data-label="${d.label}"
        style="background:${d.color}22;border:1px solid ${d.color}55;color:${d.color};">
        <span style="font-size:13px;font-weight:700;">${d.ms}ms</span>
        <span style="font-size:10px;display:block;margin-top:2px;">${d.label}</span>
      </button>
    `).join('');

    const regionBadges = Object.entries({
      'Instantaneous': { range: '< 100ms', note: 'Below perceptual threshold', color: '#888' },
      'Interactive': { range: '100–250ms', note: 'The "interactive window" — feels immediate', color: '#007755' },
      'Noticeable': { range: '250–500ms', note: 'Transition is perceptible — use intentionally', color: '#0055bb' },
      'Deliberate': { range: '500–750ms', note: 'User expects significance', color: '#7700cc' },
      'Slow': { range: '750ms+', note: 'Requires clear narrative purpose', color: '#c41c1c' },
    }).map(([label, d]) => `
      <div style="display:flex;gap:8px;align-items:flex-start;margin-bottom:8px;">
        <div style="width:10px;height:10px;border-radius:50%;background:${d.color};margin-top:3px;flex-shrink:0;"></div>
        <div>
          <span style="font-size:12px;font-weight:700;color:${d.color};">${label} (${d.range})</span>
          <div style="font-size:12px;color:#555;">${d.note}</div>
        </div>
      </div>
    `).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        .dur-grid { display: grid; grid-template-columns: repeat(5, 1fr); gap: 8px; margin-bottom: 32px; }
        .dur-btn { padding: 10px 8px; border-radius: 6px; cursor: pointer; font-family: inherit;
          text-align: center; transition: transform 0.1s; }
        .dur-btn:hover { transform: scale(1.03); }
        .dur-btn.active { outline: 2px solid currentColor; }
        .stage { width: 400px; height: 64px; background: #e8e8e8; border-radius: 8px;
          position: relative; margin-bottom: 16px; overflow: hidden; }
        .ref-box { width: 56px; height: 56px; background: #333; border-radius: 8px;
          position: absolute; left: 4px; top: 4px; }
        .active-label { font-size: 13px; font-family: monospace; color: #333; margin-bottom: 8px;
          min-height: 20px; }
        .detail-note { font-size: 12px; color: #777; margin-bottom: 32px; min-height: 18px; }
        .regions { margin-top: 8px; }
      </style>
      <div class="page">
        <div class="page-title">Experimental / Perception</div>
        <div class="page-subtitle">Duration threshold</div>
        <div class="page-desc">
          Click any duration to animate the reference box. The goal: calibrate your sense of
          what 100ms, 300ms, and 700ms feel like in practice — and why the thresholds matter.
        </div>
        <div class="dur-grid">${buttons}</div>
        <div class="active-label" id="activeLabel">Click a duration above</div>
        <div class="stage">
          <div class="ref-box" id="box"></div>
        </div>
        <div class="detail-note" id="detailNote"></div>
        <div class="regions">${regionBadges}</div>
      </div>
    `;

    const box = el.querySelector('#box');
    const activeLabel = el.querySelector('#activeLabel');
    const detailNote = el.querySelector('#detailNote');

    el.querySelectorAll('.dur-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        el.querySelectorAll('.dur-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        const ms = parseInt(btn.dataset.ms, 10);
        const label = btn.dataset.label;
        const region = DURATION_REGIONS.find(d => d.ms === ms);

        activeLabel.textContent = `${ms}ms — ${label}`;
        detailNote.textContent = region?.note || '';
        btn.style.outline = '2px solid currentColor';

        box.style.background = regionColors[label] || '#333';
        box.animate(
          [{ transform: 'translateX(0px)' }, { transform: 'translateX(320px)' }, { transform: 'translateX(0px)' }],
          { duration: ms * 2, easing: 'cubic-bezier(0.2, 0, 0, 1)', fill: 'forwards' }
        );
      });
    });

    return el;
  },
};

// ---------------------------------------------------------------------------
// Story 2 — EasingCharacter
// ---------------------------------------------------------------------------
const EASING_TRACKS = [
  { name: 'linear',    curve: [0, 0, 1, 1],    color: '#888',   label: 'Linear — mechanical, no acceleration' },
  { name: 'enter',     curve: [0, 0, 0.2, 1],  color: '#007755',label: 'Enter — decelerate into presence' },
  { name: 'exit',      curve: [0.4, 0, 1, 1],  color: '#c41c1c',label: 'Exit — accelerate out' },
  { name: 'standard',  curve: [0.4, 0, 0.2, 1],color: '#0055bb',label: 'Standard — default movement within screen' },
  { name: 'emphasize', curve: [0.2, 0, 0, 1],  color: '#7700cc',label: 'Emphasize — attention-drawing' },
];

export const EasingCharacter = {
  name: 'Easing character',
  render: () => {
    const tracks = EASING_TRACKS.map((e, i) => `
      <div style="margin-bottom:20px;">
        <div style="display:flex;align-items:center;gap:12px;margin-bottom:6px;">
          <span style="font-size:12px;font-weight:700;color:${e.color};min-width:100px;">${e.name}</span>
          <span style="font-size:11px;color:#777;">${e.label}</span>
        </div>
        <div class="track" style="background:#f0f0f0;">
          <div class="track-box" id="track_${i}" style="background:${e.color};"></div>
        </div>
      </div>
    `).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        .play-btn { padding: 10px 28px; background: #111; color: #fff; border: none;
          border-radius: 6px; font-size: 14px; font-weight: 600; cursor: pointer;
          font-family: inherit; margin-bottom: 40px; }
        .play-btn:disabled { opacity: 0.5; cursor: default; }
        .track { width: 100%; max-width: 500px; height: 36px; border-radius: 6px; position: relative; overflow: hidden; }
        .track-box { width: 36px; height: 36px; border-radius: 6px; position: absolute; left: 0; top: 0; }
      </style>
      <div class="page">
        <div class="page-title">Experimental / Perception</div>
        <div class="page-subtitle">Easing character</div>
        <div class="page-desc">
          5 primitive easing curves animated simultaneously. Same duration (500ms), same distance (200px).
          Observe how the curves feel different despite covering the same distance in the same time.
          Linear feels mechanical. Enter decelerates into presence. Exit accelerates out.
        </div>
        <button class="play-btn" id="playBtn">Play all simultaneously</button>
        ${tracks}
      </div>
    `;

    el.querySelector('#playBtn').addEventListener('click', function() {
      this.disabled = true;
      let done = 0;
      EASING_TRACKS.forEach((e, i) => {
        const box = el.querySelector(`#track_${i}`);
        const bezier = cubicBezierCSS(e.curve);
        const anim = box.animate(
          [{ transform: 'translateX(0px)' }, { transform: 'translateX(460px)' }],
          { duration: 500, easing: bezier, fill: 'forwards' }
        );
        anim.onfinish = () => {
          done++;
          if (done === EASING_TRACKS.length) {
            setTimeout(() => {
              EASING_TRACKS.forEach((e2, j) => {
                const b = el.querySelector(`#track_${j}`);
                b.animate(
                  [{ transform: 'translateX(460px)' }, { transform: 'translateX(0px)' }],
                  { duration: 500, easing: cubicBezierCSS(e2.curve), fill: 'forwards' }
                );
              });
              setTimeout(() => { this.disabled = false; }, 600);
            }, 400);
          }
        };
      });
    });

    return el;
  },
};

// ---------------------------------------------------------------------------
// Story 3 — SpringVsCubic
// ---------------------------------------------------------------------------
export const SpringVsCubic = {
  name: 'Spring vs cubic',
  render: () => {
    const gentleSpring = SPRING_CONFIGS.gentle; // { stiffness: 200, damping: 20, mass: 1 }
    const { css: springCSS, duration: springDuration } = springToLinear(
      gentleSpring.stiffness, gentleSpring.damping, gentleSpring.mass
    );
    const cubicEnter = [0, 0, 0.2, 1]; // motion.easing.enter — same conceptual intent
    const cubicDuration = springDuration; // same duration for fair comparison

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        .two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; margin-bottom: 40px; }
        .col-title { font-size: 14px; font-weight: 700; color: #111; margin-bottom: 4px; }
        .col-sub { font-size: 12px; color: #777; margin-bottom: 16px; line-height: 1.5; }
        .stage { height: 64px; background: #f0f0f0; border-radius: 8px; position: relative;
          margin-bottom: 12px; overflow: hidden; }
        .ref-box { width: 56px; height: 56px; border-radius: 8px; position: absolute; left: 4px; top: 4px; }
        .params { font-size: 11px; font-family: monospace; color: #555; line-height: 1.8; }
        .play-btn { padding: 10px 28px; background: #111; color: #fff; border: none;
          border-radius: 6px; font-size: 14px; font-weight: 600; cursor: pointer;
          font-family: inherit; margin-bottom: 40px; }
        .play-btn:disabled { opacity: 0.5; cursor: default; }
        .explanation { background: #f0f0f0; border-radius: 8px; padding: 16px 20px;
          font-size: 13px; color: #333; line-height: 1.6; }
      </style>
      <div class="page">
        <div class="page-title">Experimental / Perception</div>
        <div class="page-subtitle">Spring vs cubic-bezier</div>
        <div class="page-desc">
          Left: the <code style="font-family:monospace;background:#eee;padding:1px 4px;border-radius:3px;">motion.spring.gentle</code>
          config resolved to CSS linear(). Right: <code style="font-family:monospace;background:#eee;padding:1px 4px;border-radius:3px;">motion.easing.enter</code>
          at the same duration. Animate both simultaneously. The spring settles organically;
          the cubic-bezier is a fixed geometric curve.
        </div>
        <button class="play-btn" id="playBtn">Play simultaneously</button>
        <div class="two-col">
          <div>
            <div class="col-title">Spring — motion.spring.gentle</div>
            <div class="col-sub">Resolved to CSS linear() via spring resolver.<br>Settles organically.</div>
            <div class="stage">
              <div class="ref-box" id="springBox" style="background:#7700cc;"></div>
            </div>
            <div class="params">
              stiffness: ${gentleSpring.stiffness}<br>
              damping: ${gentleSpring.damping}<br>
              mass: ${gentleSpring.mass}<br>
              settlement: ~${springDuration}ms
            </div>
          </div>
          <div>
            <div class="col-title">Cubic-bezier — motion.easing.enter</div>
            <div class="col-sub">Fixed geometric curve at ${cubicDuration}ms.<br>Deterministic endpoint.</div>
            <div class="stage">
              <div class="ref-box" id="cubicBox" style="background:#0055bb;"></div>
            </div>
            <div class="params">
              ${cubicBezierCSS(cubicEnter)}<br>
              duration: ${cubicDuration}ms (matched)<br>
              <br>
              fixed curve
            </div>
          </div>
        </div>
        <div class="explanation">
          <strong>The difference:</strong> Both cover the same distance in approximately the same time.
          The spring's acceleration profile emerges from physics equations — it responds continuously and
          can be interrupted mid-motion. The cubic-bezier is pre-committed to a fixed curve shape.
          The visual difference is subtle but present, especially on the initial acceleration.
          On interrupted or redirected animations, the spring behaves more naturally.
        </div>
      </div>
    `;

    const springBox = el.querySelector('#springBox');
    const cubicBox = el.querySelector('#cubicBox');
    const playBtn = el.querySelector('#playBtn');
    let playing = false;

    playBtn.addEventListener('click', () => {
      if (playing) return;
      playing = true;
      playBtn.disabled = true;

      const travel = 200;

      springBox.animate(
        [{ transform: 'translateX(0px)' }, { transform: `translateX(${travel}px)` }],
        { duration: springDuration, easing: springCSS, fill: 'forwards' }
      );

      const cubicAnim = cubicBox.animate(
        [{ transform: 'translateX(0px)' }, { transform: `translateX(${travel}px)` }],
        { duration: cubicDuration, easing: cubicBezierCSS(cubicEnter), fill: 'forwards' }
      );

      cubicAnim.onfinish = () => {
        setTimeout(() => {
          springBox.animate(
            [{ transform: `translateX(${travel}px)` }, { transform: 'translateX(0px)' }],
            { duration: springDuration, easing: springCSS, fill: 'forwards' }
          );
          cubicBox.animate(
            [{ transform: `translateX(${travel}px)` }, { transform: 'translateX(0px)' }],
            { duration: cubicDuration, easing: cubicBezierCSS(cubicEnter), fill: 'forwards' }
          ).onfinish = () => {
            playing = false;
            playBtn.disabled = false;
          };
        }, 300);
      };
    });

    return el;
  },
};

